import{_ as e,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Invalid Grant トラブルシューティング: アカウント無効化と復旧 | Antigravity-Manager","description":"invalid_grant エラーの意味と自動処理ロジックを学びます。refresh_token 失効を確認した後、再度 OAuth でアカウントを追加して自動無効化を解除し、復旧が Proxy に有効になったかを検証します。","frontmatter":{"title":"Invalid Grant トラブルシューティング: アカウント無効化と復旧 | Antigravity-Manager","sidebarTitle":"アカウントが無効化されたらどう回復するか","subtitle":"invalid_grant とアカウント自動無効化：なぜ発生するか、どう回復するか","description":"invalid_grant エラーの意味と自動処理ロジックを学びます。refresh_token 失効を確認した後、再度 OAuth でアカウントを追加して自動無効化を解除し、復旧が Proxy に有効になったかを検証します。","tags":["FAQ","エラートラブルシューティング","OAuth","アカウント管理","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":1},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),o={name:"ja/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function d(n,a,s,l,c,h){return r(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="invalid-grant-とアカウント自動無効化-なぜ発生するか、どう回復するか" tabindex="-1">invalid_grant とアカウント自動無効化：なぜ発生するか、どう回復するか <a class="header-anchor" href="#invalid-grant-とアカウント自動無効化-なぜ発生するか、どう回復するか" aria-label="Permalink to &quot;invalid_grant とアカウント自動無効化：なぜ発生するか、どう回復するか&quot;">​</a></h1><h2 id="学んだ後できること" tabindex="-1">学んだ後できること <a class="header-anchor" href="#学んだ後できること" aria-label="Permalink to &quot;学んだ後できること&quot;">​</a></h2><ul><li><code>invalid_grant</code> を見たとき、どの refresh_token 問題に対応しているかを知る</li><li>「アカウントがなぜ突然使えなくなったのか」を明確にする：どのような状況で自動的に無効化されるか、無効化後にシステムがどう処理するか</li><li>最短パスでアカウントを回復し、回復が実行中の Proxy に有効になったかを確認</li></ul><h2 id="現在遭遇している症状" tabindex="-1">現在遭遇している症状 <a class="header-anchor" href="#現在遭遇している症状" aria-label="Permalink to &quot;現在遭遇している症状&quot;">​</a></h2><ul><li>ローカル Proxy を呼び出すときに突然失敗し、エラーメッセージに <code>invalid_grant</code> が現れる</li><li>明らかにアカウントはまだ Accounts リストにあるのに、Proxy はずっとそれをスキップする（または「もう使われていない」と感じる）</li><li>アカウント数が少ない時、一度 <code>invalid_grant</code> に遭遇した後、全体の可用性が明らかに悪化</li></ul><h2 id="invalid-grant-とは" tabindex="-1">invalid_grant とは？ <a class="header-anchor" href="#invalid-grant-とは" aria-label="Permalink to &quot;invalid_grant とは？&quot;">​</a></h2><p><strong>invalid_grant</strong> は Google OAuth が <code>access_token</code> をリフレッシュする際に返すエラーのカテゴリです。Antigravity Tools にとって、それはあるアカウントの <code>refresh_token</code> がすでに取り消されたか期限切れの可能性が高いことを意味し、再試行しても繰り返し失敗するため、システムはそのアカウントを利用不可としてマークし、プロキシプールから除外します。</p><h2 id="コアコンセプト-システムは「一時的にスキップ」ではなく「永続的に無効化」" tabindex="-1">コアコンセプト：システムは「一時的にスキップ」ではなく「永続的に無効化」 <a class="header-anchor" href="#コアコンセプト-システムは「一時的にスキップ」ではなく「永続的に無効化」" aria-label="Permalink to &quot;コアコンセプト：システムは「一時的にスキップ」ではなく「永続的に無効化」&quot;">​</a></h2><p>Proxy が token リフレッシュのエラー文字列に <code>invalid_grant</code> が含まれるのを検出したとき、2 つのことを行います：</p><ol><li><strong>アカウントを disabled に書く</strong>（アカウント JSON に保存）</li><li><strong>アカウントをメモリの token pool から削除</strong>（同じ悪いアカウントを繰り返し選択するのを避ける）</li></ol><p>これが「アカウントはあるのに、Proxy はもう使わない」ことの理由です。</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>：アカウントが「完全に無効化」（典型的な原因は <code>invalid_grant</code>）。アカウントプールをロードする時に直接スキップ</li><li><code>proxy_disabled=true</code>：アカウントは「Proxy に対して利用不可」（手動無効化/バッチ操作/クォータ保護関連ロジック）、意味が異なる</li></ul><p>この 2 つの状態はアカウントプールをロードする時に分けて判断されます：先に <code>disabled</code> を判断し、その後クォータ保護と <code>proxy_disabled</code> 判断を行います。</p></div><h2 id="手順通りに進める" tabindex="-1">手順通りに進める <a class="header-anchor" href="#手順通りに進める" aria-label="Permalink to &quot;手順通りに進める&quot;">​</a></h2><h3 id="第-1-ステップ-refresh-token-リフレッシュがトリガーした-invalid-grant-か確認" tabindex="-1">第 1 ステップ：refresh_token リフレッシュがトリガーした invalid_grant か確認 <a class="header-anchor" href="#第-1-ステップ-refresh-token-リフレッシュがトリガーした-invalid-grant-か確認" aria-label="Permalink to &quot;第 1 ステップ：refresh_token リフレッシュがトリガーした invalid_grant か確認&quot;">​</a></h3><p><strong>なぜか</strong>：<code>invalid_grant</code> は複数の呼び出しチェーンに現れる可能性がありますが、このプロジェクトの「自動無効化」は<strong>access_token リフレッシュ失敗</strong>時のみトリガーされます。</p><p>Proxy ログで、類似のエラーログが見えます（キーワードは <code>Token 刷新失敗</code> + <code>invalid_grant</code>）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 刷新失敗 (&lt;email&gt;): &lt;...invalid_grant...&gt;，尝试下一个账号</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>表示されるべきもの</strong>：同じアカウントが <code>invalid_grant</code> に出現した後、すぐに選択されなくなります（token pool から削除されたため）。</p><h3 id="第-2-ステップ-アカウントファイルで-disabled-フィールドを確認-オプションだが最も正確" tabindex="-1">第 2 ステップ：アカウントファイルで disabled フィールドを確認（オプションだが最も正確） <a class="header-anchor" href="#第-2-ステップ-アカウントファイルで-disabled-フィールドを確認-オプションだが最も正確" aria-label="Permalink to &quot;第 2 ステップ：アカウントファイルで disabled フィールドを確認（オプションだが最も正確）&quot;">​</a></h3><p><strong>なぜか</strong>：自動無効化は「保存」されるため、ファイル内容を確認すると、「一時的なローテーション」の誤判を排除できます。</p><p>アカウントファイルはアプリデータディレクトリの <code>accounts/</code> ディレクトリにあります（データディレクトリの場所は <strong><a href="./../../start/first-run-data/">初回起動必読：データディレクトリ、ログ、トレイと自動起動</a></strong> を参照）。アカウントが無効化された時、ファイルにこの 3 つのフィールドが現れます：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>表示されるべきもの</strong>：<code>disabled</code> が <code>true</code> で、<code>disabled_reason</code> に <code>invalid_grant:</code> プレフィックスが含まれる。</p><h3 id="第-3-ステップ-アカウントを回復-推奨做法-同じアカウントを再度追加" tabindex="-1">第 3 ステップ：アカウントを回復（推奨做法：同じアカウントを再度追加） <a class="header-anchor" href="#第-3-ステップ-アカウントを回復-推奨做法-同じアカウントを再度追加" aria-label="Permalink to &quot;第 3 ステップ：アカウントを回復（推奨做法：同じアカウントを再度追加）&quot;">​</a></h3><p><strong>なぜか</strong>：このプロジェクトの「回復」は Proxy でスイッチを手動でクリックすることではなく、「明示的に token を更新」して自動無効化を解除することをトリガーします。</p><p><strong>Accounts</strong> ページで、新しい認証情報を使って再度アカウントを追加します（いずれかの方法を選択）：</p><ol><li>OAuth 認証フローを再度通す（<strong><a href="./../../start/add-account/">アカウント追加：OAuth/Refresh Token デュアルチャネルとベストプラクティス</a></strong> を参照）</li><li>新しい <code>refresh_token</code> を使って再度追加（システムは Google が返したメールを基準に upsert）</li></ol><p>システムが今回 upsert した <code>refresh_token</code> または <code>access_token</code> が旧値と異なり、かつそのアカウントが以前 <code>disabled=true</code> だったことを検出したとき、自動的にクリアします：</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>表示されるべきもの</strong>：アカウントはもう disabled 状態ではなく、かつ（Proxy が実行中なら）アカウントプールが自動的にリロードされ、回復が直ちに有効になります。</p><h3 id="第-4-ステップ-回復が-proxy-に有効になったか検証" tabindex="-1">第 4 ステップ：回復が Proxy に有効になったか検証 <a class="header-anchor" href="#第-4-ステップ-回復が-proxy-に有効になったか検証" aria-label="Permalink to &quot;第 4 ステップ：回復が Proxy に有効になったか検証&quot;">​</a></h3><p><strong>なぜか</strong>：アカウントが 1 つだけの場合、または他のアカウントも利用不可の場合、回復後すぐに「可用性が戻ってきた」のが見えるはずです。</p><p>検証方法：</p><ol><li>token リフレッシュをトリガーするリクエストを一度行う（例：token の期限切れが近づいてからリクエスト）</li><li>ログでもう「disabled アカウントをスキップ」の提示が出ないことを観察</li></ol><p><strong>表示されるべきもの</strong>：リクエストが正常に通り、ログでもはやそのアカウントに対する <code>invalid_grant</code> 無効化フローが出ない。</p><h2 id="罠の警告" tabindex="-1">罠の警告 <a class="header-anchor" href="#罠の警告" aria-label="Permalink to &quot;罠の警告&quot;">​</a></h2><h3 id="❌-disabled-を「一時的なローテーション」と間違える" tabindex="-1">❌ disabled を「一時的なローテーション」と間違える <a class="header-anchor" href="#❌-disabled-を「一時的なローテーション」と間違える" aria-label="Permalink to &quot;❌ disabled を「一時的なローテーション」と間違える&quot;">​</a></h3><p>UI だけで「アカウントはある」と見ると、誤って「システムは一時的に使っていないだけ」と判断しやすいです。しかし <code>disabled=true</code> はディスクに書かれており、再起動後も引き続き有効になります。</p><h3 id="❌-access-token-だけを補充し、refresh-token-を更新しない" tabindex="-1">❌ access_token だけを補充し、refresh_token を更新しない <a class="header-anchor" href="#❌-access-token-だけを補充し、refresh-token-を更新しない" aria-label="Permalink to &quot;❌ access_token だけを補充し、refresh_token を更新しない&quot;">​</a></h3><p><code>invalid_grant</code> のトリガーポイントは <code>access_token</code> をリフレッシュする時に使用した <code>refresh_token</code> です。一時的にまだ使える <code>access_token</code> を取得しても、<code>refresh_token</code> は依然として無効であれば、後で再び無効化がトリガーされます。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>[ ] ログで <code>invalid_grant</code> が refresh_token リフレッシュ失敗から来ることを確認できる</li><li>[ ] <code>disabled</code> と <code>proxy_disabled</code> の意味の違いを知っている</li><li>[ ] アカウントを再度追加（OAuth または refresh_token）してアカウントを回復できる</li><li>[ ] 回復が実行中の Proxy に有効になったか検証できる</li></ul><h2 id="レッスンまとめ" tabindex="-1">レッスンまとめ <a class="header-anchor" href="#レッスンまとめ" aria-label="Permalink to &quot;レッスンまとめ&quot;">​</a></h2><ul><li><code>invalid_grant</code> がトリガーされると、Proxy はアカウントを <strong>disabled として保存</strong>し、token pool から削除し、繰り返し失敗することを回避</li><li>回復の鍵は「明示的に token を更新」すること（再度 OAuth または新 refresh_token で再度追加）、システムは自動的に <code>disabled_*</code> フィールドをクリア</li><li>データディレクトリのアカウント JSON が最も権威のある状態のソース（無効化/原因/時間がすべて含まれる）</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../auth-401/">401/認証失敗：auth_mode、Header 互換性とクライアント設定チェックリスト</a></strong> を学びます</p><p>学べること：</p><ul><li>401 は通常「モード/Key/Header」のどのレイヤーが不一致か</li><li>異なるクライアントはどの認証 Header を持つべきか</li><li>最短パスで自己検証し修正する方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>設計説明：invalid_grant の問題と変更動作</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>アカウントプールをロードする時に <code>disabled=true</code> をスキップ</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>token リフレッシュ失敗時に <code>invalid_grant</code> を識別しアカウントを無効化</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td><code>disabled/disabled_at/disabled_reason</code> を永続化して書き込み、メモリから削除</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td><code>disabled_reason</code> トリミング（アカウントファイル肥大化回避）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>upsert 時に自動的に <code>disabled_*</code> をクリア（token 変更＝ユーザーが認証情報を修復したと見なす）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L178-L206" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>178-206</td></tr><tr><td>アカウントを再度追加後、自動的に proxy accounts をリロード（実行中に直ちに有効）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L21-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>21-59</td></tr></tbody></table></details>`,49)])])}const u=e(o,[["render",d]]);export{p as __pageData,u as default};
